const byId=Object.fromEntries(graphNodes.map(n=>[n.id,n]));
let graphState={scale:1,x:0,y:0,filter:'all',drag:false,lastX:0,lastY:0};
let compatIndex=0;
let relationIndex=-1;
function shuffle(a){return [...a].sort(()=>Math.random()-.5)}
function pickTypeAlias(index,side){const list=I18N[currentLang].typeAliases?.[index]?.[side==='left'?0:1]||[];return list[Math.floor(Math.random()*list.length)]||''}
function renderRelationLabel(index){const list=(I18N[currentLang].relations||I18N.uk.relations)[index]||[];relationIndex=(relationIndex+1+Math.floor(Math.random()*Math.max(1,list.length-1)))%list.length;document.querySelectorAll('[data-relation-label]').forEach(el=>el.textContent=list[relationIndex]||'')}
function renderSilhouetteModels(index){const configs=[{cls:'temporistics',title:['Темпористика','Temporistics','Темпористика'],items:['Мин','Теп','Май','Віч']},{cls:'afanasyev',title:['Модель Афанасьєва','Afanasyev Model','Модель Афанасьєва'],items:['Воля','Лог','Емо','Фіз']},{cls:'model-a',title:['Модель A','Model A','Модель A'],items:['Ti','Te','Fi','Fe','Si','Se','Ni','Ne']}];const langIndex={ru:0,en:1,uk:2}[currentLang]||0;document.querySelectorAll('[data-model-side]').forEach(el=>{const cfg=configs[index];const items=shuffle(cfg.items);const side=el.dataset.modelSide;el.innerHTML=`<div class="type-alias">${pickTypeAlias(index,side)}</div><div class="model-title">${cfg.title[langIndex]}</div><div class="model-grid ${cfg.cls}">${items.map((it,i)=>`<div class="model-cell"><span>${it}</span><small>${i+1}</small></div>`).join('')}</div>`})}
function updateCompatibilityBadge(index=compatIndex){const changed=index!==compatIndex;compatIndex=index;const item=(I18N[currentLang].compat||I18N.ru.compat)[index];document.body.style.setProperty('--compat-color',item[2]);document.querySelectorAll('[data-compat-label]').forEach(el=>el.textContent=item[0]);document.querySelectorAll('[data-compat-system]').forEach(el=>el.textContent=item[1]);document.querySelector('[data-mobile-level]').textContent=item[0];document.querySelector('[data-mobile-system]').textContent=item[1];renderSilhouetteModels(index);if(changed||relationIndex<0)renderRelationLabel(index)}
function renderDynamic(){const chipClasses=['chip-strategy','chip-action','chip-contact'];document.querySelector('#levelCards').innerHTML=levels.map((l,i)=>`<article class="card level-card"><span class="chip ${chipClasses[i]||''}">${l.system}</span><h3>${l.n} · ${l.ru}</h3><p><b>${l.process}</b></p><p>${l.q}</p><p class="focus-line">${l.focus}</p></article>`).join('');document.querySelector('#pipeline').innerHTML=I18N[currentLang].pipeline.map((s,i)=>`<div class="step"><b>0${i+1}</b> ${s}</div>`).join('');document.querySelector('#pageCards').innerHTML=pages.map(p=>`<article class="page"><h3>${p[1]}</h3><p>${p[2]}</p><a href="https://github.com/before-we-build/before-we-build-research/blob/main/wiki/concepts/${p[0]}.md">${I18N[currentLang]['link.open']}</a></article>`).join('')}
function setLayer(index){const data=I18N[currentLang].layerExplain[index];document.querySelectorAll('[data-layer]').forEach(b=>b.classList.toggle('active',Number(b.dataset.layer)===index));document.querySelector('[data-layer-title]').textContent=data[0];document.querySelector('[data-layer-text]').textContent=data[1];document.querySelector('[data-layer-example]').textContent=data[2];updateCompatibilityBadge(index)}
function applyLanguage(lang){currentLang=I18N[lang]?lang:'uk';const dict=I18N[currentLang];document.documentElement.lang=currentLang;localStorage.setItem('before-we-build-lang',currentLang);document.querySelectorAll('[data-i18n]').forEach(el=>{const value=dict[el.dataset.i18n];if(value)el.textContent=value});levels=dict.levels.map(([n,ru,system,color,process,q,focus])=>({n,ru,system,color,process,q,focus}));pages=dict.pages;document.querySelectorAll('[data-lang]').forEach(b=>{const active=b.dataset.lang===currentLang;b.classList.toggle('active',active);b.setAttribute('aria-pressed',String(active))});renderDynamic();renderProcessMechanics();setLayer(compatIndex);if(typeof draw==='function')draw()}
document.querySelectorAll('[data-lang]').forEach(b=>b.addEventListener('click',()=>applyLanguage(b.dataset.lang)));
document.querySelectorAll('[data-layer]').forEach(b=>b.addEventListener('click',()=>{document.querySelector('#layerViz')?.classList.remove('showing-all');setLayer(Number(b.dataset.layer))}));
document.querySelector('[data-show-layers]')?.addEventListener('click',()=>document.querySelector('#layerViz')?.classList.toggle('showing-all'));
function draw(filter=graphState.filter){graphState.filter=filter;const langIndex={ru:0,en:1,uk:2}[currentLang]||0;const active=n=>filter==='all'||n.group===filter;const color=n=>n.group==='research'?'var(--color-warning)':n.group==='systems'?'var(--color-accent)':n.group==='application'?'var(--color-warning)':'var(--color-primary)';const lines=graphLinks.map(([a,b])=>{const A=byId[a],B=byId[b],dim=!(active(A)||active(B));return`<line x1="${A.x}" y1="${A.y}" x2="${B.x}" y2="${B.y}" stroke="var(--color-border)" stroke-width="2" class="${dim?'dim':''}"/>`}).join('');const ns=graphNodes.map(n=>{const label=n.label[langIndex]||n.label[1];const url=`https://github.com/before-we-build/before-we-build-research/search?q=${encodeURIComponent(n.id)}`;return`<g data-href="${url}" class="graph-node ${active(n)?'':'dim'}" role="link" tabindex="0" aria-label="${label}"><circle cx="${n.x}" cy="${n.y}" r="46" fill="${color(n)}" opacity=".16" stroke="${color(n)}" stroke-width="2"/><text x="${n.x}" y="${n.y-3}" text-anchor="middle" class="svg-label">${label}</text><text x="${n.x}" y="${n.y+15}" text-anchor="middle" class="svg-group">${n.group}</text></g>`}).join('');document.querySelector('#wikiGraph').innerHTML=`<g transform="translate(${graphState.x} ${graphState.y}) scale(${graphState.scale})">${lines}${ns}</g>`}applyLanguage(currentLang);draw();
document.querySelectorAll('[data-filter]').forEach(b=>b.addEventListener('click',()=>{document.querySelectorAll('[data-filter]').forEach(x=>x.setAttribute('aria-pressed',String(x===b)));draw(b.dataset.filter)}));document.querySelector('[data-filter="all"]')?.setAttribute('aria-pressed','true');
const graphSvg=document.querySelector('#wikiGraph'),graphPanel=document.querySelector('#graphPanel');
function zoomGraph(mult){graphState.scale=Math.max(.35,Math.min(3.2,graphState.scale*mult));draw()}
document.querySelectorAll('[data-zoom]').forEach(b=>b.addEventListener('click',()=>{const z=b.dataset.zoom;if(z==='in')zoomGraph(1.18);if(z==='out')zoomGraph(.85);if(z==='reset'){graphState.scale=1;graphState.x=0;graphState.y=0;draw()}}));
document.querySelector('[data-fullscreen]')?.addEventListener('click',()=>{if(!document.fullscreenElement)graphPanel?.requestFullscreen?.();else document.exitFullscreen?.()});
if(graphSvg){graphSvg.addEventListener('wheel',e=>{e.preventDefault();zoomGraph(e.deltaY<0?1.08:.92)},{passive:false});graphSvg.addEventListener('pointerdown',e=>{graphState.drag=true;graphState.moved=false;graphState.lastX=e.clientX;graphState.lastY=e.clientY;graphPanel?.classList.add('is-dragging');graphSvg.setPointerCapture(e.pointerId);graphSvg.style.cursor='grabbing'});graphSvg.addEventListener('pointermove',e=>{if(!graphState.drag)return;const dx=e.clientX-graphState.lastX,dy=e.clientY-graphState.lastY;if(Math.abs(dx)+Math.abs(dy)>3)graphState.moved=true;graphState.x+=dx;graphState.y+=dy;graphState.lastX=e.clientX;graphState.lastY=e.clientY;draw()});graphSvg.addEventListener('pointerup',e=>{const node=e.target.closest?.('[data-href]');if(node&&!graphState.moved)window.open(node.dataset.href,'_blank','noopener');graphState.drag=false;graphPanel?.classList.remove('is-dragging');graphSvg.style.cursor='grab'});graphSvg.addEventListener('keydown',e=>{const node=e.target.closest?.('[data-href]');if(node&&(e.key==='Enter'||e.key===' ')){e.preventDefault();window.open(node.dataset.href,'_blank','noopener')}});graphSvg.addEventListener('pointerleave',()=>{graphState.drag=false;graphPanel?.classList.remove('is-dragging');graphSvg.style.cursor='grab'})}
function trackCompatibilityLevel(){const points=[['model',0],['strategic',0],['operational',1],['layers',1],['tactical',2],['graph',2],['pages',2]];let best=0,bestDist=Infinity;points.forEach(([id,idx])=>{const el=document.getElementById(id);if(!el)return;const d=Math.abs(el.getBoundingClientRect().top-window.innerHeight*.38);if(d<bestDist){bestDist=d;best=idx}});updateCompatibilityBadge(best)}
window.addEventListener('scroll',()=>requestAnimationFrame(trackCompatibilityLevel),{passive:true});
window.addEventListener('resize',trackCompatibilityLevel);
trackCompatibilityLevel();

