function renderTests(){
  const tabs=document.querySelector('#testTabs'),panel=document.querySelector('#testPanel');
  if(!tabs||!panel)return;
  const dict=I18N[currentLang]||I18N.ru;
  tabs.innerHTML=Object.entries(TESTS).map(([key,test])=>`<button type="button" class="${key===activeTest?'active':''}" aria-pressed="${key===activeTest}" data-test-key="${key}">${test.labels[currentLang]?.[0]||test.labels.ru[0]}</button>`).join('');
  const test=TESTS[activeTest];
  const label=test.labels[currentLang]||test.labels.ru;
  const items=test.items[currentLang]||test.items.ru;
  panel.innerHTML=`<div class="test-meta"><h3>${label[0]}</h3><p>${label[1]}</p><p>${dict['tests.caveat']}</p></div><div class="test-items">${items.map((item,i)=>`<article class="test-item" data-test-item="${i}"><p><b>${i+1}.</b> ${item[0]}</p><div class="scale">${[1,2,3,4,5,6].map(v=>`<label><input type="radio" name="${activeTest}-${i}" value="${v}">${v}</label>`).join('')}</div><div class="scale-help"><span>${dict['tests.scale.left']}</span><span>${dict['tests.scale.right']}</span></div></article>`).join('')}</div><div class="test-actions"><button type="button" class="primary" data-test-submit>${dict['tests.submit']}</button><button type="button" data-test-reset>${dict['tests.reset']}</button></div><div id="testResult" aria-live="polite"></div>`;
  tabs.querySelectorAll('[data-test-key]').forEach(b=>b.addEventListener('click',()=>{activeTest=b.dataset.testKey;renderTests()}));
  panel.querySelector('[data-test-submit]')?.addEventListener('click',scoreActiveTest);
  panel.querySelector('[data-test-reset]')?.addEventListener('click',renderTests);
}
function scoreActiveTest(){
  const dict=I18N[currentLang]||I18N.ru,test=TESTS[activeTest],items=test.items[currentLang]||test.items.ru;
  const scores=Object.fromEntries(test.dims.map(d=>[d,0])),counts=Object.fromEntries(test.dims.map(d=>[d,0]));
  let missing=false;
  document.querySelectorAll('[data-test-item]').forEach(el=>el.classList.remove('missing-answer'));
  items.forEach((item,i)=>{const checked=document.querySelector(`input[name="${activeTest}-${i}"]:checked`);if(!checked){missing=true;document.querySelector(`[data-test-item="${i}"]`)?.classList.add('missing-answer');return}scores[item[1]]+=Number(checked.value);counts[item[1]]+=1});
  const out=document.querySelector('#testResult');
  if(missing){out.innerHTML=`<div class="test-result"><p class="test-caveat">${dict['tests.missing']}</p></div>`;return}
  const rows=test.dims.map(d=>[d,counts[d]?scores[d]/counts[d]:0]).sort((a,b)=>b[1]-a[1]);
  const top=rows.slice(0,3).map(r=>r[0]).join(' · ');
  out.innerHTML=`<div class="test-result"><h4>${dict['tests.result']}: ${top}</h4><div class="result-bars">${rows.map(([d,v])=>`<div class="result-row"><b>${d}</b><span class="bar-track"><span class="bar-fill" style="width:${Math.round(v/6*100)}%"></span></span><em>${v.toFixed(1)}</em></div>`).join('')}</div><p class="test-caveat">${dict['tests.caveat']}</p></div>`;
}
const applyLanguageBase=applyLanguage;
applyLanguage=function(lang){applyLanguageBase(lang);renderTests()};
renderTests();
